INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i08205pxlk9c7ys5lv2v', 'cmp5n9dkm0059gnmm2fl5fmvx', 'Кириллин Арлен', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '3', 'Прошёл полностью, документ на руках. Нормальный уровень, без лишней воды. Хотелось бы чуть больше визуализации в лекциях.', 't', '2026-04-12 16:25:14.06'),
('cmp67i08205pzlk9ck7mkods2', 'cmp5n9dko005cgnmmqnifnveg', 'Лизунов Михаил', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Завершила курс из упрямства — в целом полезно, но ожидала большей гибкости по срокам и более разжёванных объяснений в паре модулей. За идею и сертификат спасибо, за подачу — на четвёрку не потянет.', 't', '2026-04-10 16:02:05.776'),
('cmp67i08305q1lk9ct1cgva00', 'cmp5n9dkp005fgnmm79kg66hy', 'Мирзоян Диана', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-16 11:36:44.183'),
('cmp67i08605qdlk9c9l9nreog', 'cmp5n9dkw005ugnmmyitg7sjm', 'Ноговицын Альберт', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-14 01:44:01.53'),
('cmp67i08405q3lk9cfefp70ba', 'cmp5n9dkq005ignmmf85atsb3', 'Никитина Олеся', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '3', 'Ровный курс: прошла, сертификат на руках. Ни восторга, ни разочарования — как хороший учебник, только интерактивный.', 't', '2026-04-09 21:18:24.178'),
('cmp67i08405q5lk9ckhu5o82c', 'cmp5n9dks005lgnmmn6zuvpbz', 'Никифоров Ларион', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Курс в итоге закончил, но тянулось тяжело: местами слишком плотно по тексту, а обратная связь по практике шла не так быстро, как хотелось. На троечку тянет, не больше.', 't', '2026-04-14 13:02:27.682'),
('cmp67i08705qjlk9cpmbhsx69', 'cmp5n9dl00063gnmmx7qvs6xx', 'Портнягина Наина', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-16 08:50:02.318'),
('cmp67i08405q7lk9c3zj1d8g0', 'cmp5n9dkt005ognmmobt0mjis', 'Никифоров Ньургун', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Завершила курс из упрямства — в целом полезно, но ожидала большей гибкости по срокам и более разжёванных объяснений в паре модулей. За идею и сертификат спасибо, за подачу — на четвёрку не потянет.', 't', '2026-04-08 19:56:20.311'),
('cmp67i08505q9lk9c4pyd7g91', 'cmp5n9dkv005rgnmmqr22iq2w', 'Николаев Дьулуур', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-15 07:23:59.642'),
('cmp67i08605qflk9cajy5g4mz', 'cmp5n9dky005xgnmmwdy11ymy', 'Попов Герман', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Как программисту, зашло сочетание «теория + руки». Прошёл полностью. Сертификат пригодится. Не пять звёзд только из‑за пары опечаток в заданиях.', 't', '2026-04-11 08:38:33.586'),
('cmp67i08905qplk9celfr6t7h', 'cmp5n9dl3006cgnmm50xrxj6i', 'Смирников Николай', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-10 06:39:55.324'),
('cmp67i06c05j9lk9cuiej2q5c', 'cmp66xis600g6lktgm2g8yhpl', 'Огонерова Сардаана Васильевна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'Прошёл полностью, документ на руках. Нормальный уровень, без лишней воды. Хотелось бы чуть больше визуализации в лекциях.', 't', '2026-04-14 03:36:37.677'),
('cmp67i06k05k1lk9clrmjqzve', 'cmp66xiyx00h9lktgtgbw52ms', 'Васильев Роберт Денисович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '2', 'Курс закончил, но тяжеловато по нагрузке параллельно с парой. Иногда не хватало пошаговых подсказок в практике. Итог: полезно, но не идеально.', 't', '2026-04-13 00:39:42.827'),
('cmp67i08a05qvlk9cv9jbbj6o', 'cmp5n9dl8006lgnmmyxo4l8dy', 'Спиридонова Лидия', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Закончил курс, но местами было скучновато и много читать подряд. Практика спасает, но первые модули хотелось «поживее». На троечку с плюсом.', 't', '2026-04-17 08:24:05.337'),
('cmp67i08905qrlk9csk32hosm', 'cmp5n9dl6006fgnmm3s191f4z', 'Смирников Николай 2', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Хорошо стыкуется с очным расписанием: можно догнать дома. Сертификат получил. Минус — иногда неочевидно, где сохранился черновик практики.', 't', '2026-04-10 19:43:11.429'),
('cmp67i08a05qtlk9cp409nf2c', 'cmp5n9dl7006ignmmi54zz7z6', 'Соколов Егор', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '5', 'Очень понятная траектория, не расползается «водой». Дошёл до конца быстрее, чем ожидал. Сертификат — плюс к мотивации дальше копать тему.', 't', '2026-04-13 16:44:31.641'),
('cmp67i08c05qzlk9caxloefzg', 'cmp5n9dl9006ognmmtt9kb21g', 'Степанов Сергей', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '5', 'Отличный итог для второго курса: и расследование, и «собрать картину» по логам — близко к тому, что обсуждаем на парах. Курс полностью прошёл.', 't', '2026-04-15 10:46:39.566'),
('cmp67i08d05r1lk9c10khotnx', 'cmp5n9dld006rgnmm83lcz0im', 'Сысолятин Иван', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '5', 'Сильная практическая часть — после неё теория «ложится» в голову. Закрыл всё, сертификатом доволен. Рекомендую потоку.', 't', '2026-04-09 02:57:46.502'),
('cmp67i08d05r3lk9cf595s7g5', 'cmp5n9dlf006ugnmmihwm19r2', 'Таскин Валентин', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '3', 'Прошла полностью на заочке. Нормально, без сюрпризов: тесты, практика, документ. Хотелось бы чуть больше голосовых/видео пояснений, но это вкусовщина.', 't', '2026-04-12 08:03:40.886'),
('cmp67i08d05r5lk9c06t2slkr', 'cmp5n9dli006xgnmmjmlhdl7q', 'Томская Сабина', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Сдал полностью, баллы и сертификат на месте. За четыре звезды: понятная навигация, адекватные тесты, практика близкая к «жизни». Пятый балл не поставил из‑за редких мелких огрехов в формулировках заданий.', 't', '2026-04-11 12:50:36.366'),
('cmp67i08e05r7lk9ci6h0l75q', 'cmp5n9dlk0070gnmm3vs2b61g', 'Томчук Иван', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Хороший рабочий курс: и лекции, и задания, и итоговый документ. Отняла балл только то, что к концу устала от однотипных формулировок в подсказках, но по содержанию всё честно и по делу.', 't', '2026-04-12 02:27:00.692'),
('cmp67i08g05rflk9chl2xhv3j', 'cmp5neihh007cgn7xenv816yc', 'Антонов Артур', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-12 00:08:00.564'),
('cmp67i08f05rblk9cexevrnwd', 'cmp5n9dlo0076gnmmi9ani4o5', 'Яковлева Анжела', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Хороший рабочий курс: и лекции, и задания, и итоговый документ. Отняла балл только то, что к концу устала от однотипных формулировок в подсказках, но по содержанию всё честно и по делу.', 't', '2026-04-12 10:23:59.85'),
('cmp67i08f05rdlk9cbhaoeull', 'cmp5neiha0079gn7x6utkjx2s', 'Андросова Аделита', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '5', 'На втором курсе ИСИП как раз то, что нужно: и термины, и аккуратные сценарии. Прошла полностью, сертификат уже в папке с документами. Рекомендую группе.', 't', '2026-04-10 08:22:00.998'),
('cmp67i08h05rhlk9ctny1jk2q', 'cmp5neihk007fgn7xik8bhxdx', 'Артемьев Эрсан', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '4', 'Прошёл курс до конца, материал связный. Практика с обратной связью — сильная сторона. Не идеально, но уверенная четвёрка.', 't', '2026-04-15 18:13:05.374');